      howToSchema: { '@context': 'https://schema.org', '@type': 'HowTo', name: 'DГ©panner LLM Local', inLanguage: 'fr', step: [{ '@type': 'HowToStep', position: 1, name: 'VГ©rifiez VRAM disponible' }, { '@type': 'HowToStep', position: 2, name: 'VГ©rifiez les chemins de modГЁle' }, { '@type': 'HowToStep', position: 3, name: 'VГ©rifiez la quantification' }, { '@type': 'HowToStep', position: 4, name: 'VГ©rifiez les permissions' }, { '@type': 'HowToStep', position: 5, name: 'Testez avec un petit modГЁle' }] },
